import{C as n,o as s,c as i,j as a,a as r,E as l,a5 as d}from"./chunks/framework.CW28V7p_.js";const h=JSON.parse('{"title":"⭐ Module 10 — Final quiz","description":"","frontmatter":{},"headers":[],"relativePath":"module-10/final-quiz.md","filePath":"module-10/final-quiz.md","lastUpdated":1780937944000}'),c={name:"module-10/final-quiz.md"},f=Object.assign(c,{setup(u){const t={id:"m10-final",title:"⭐ Module 10 — Final quiz",intro:"6 питань — special topics.",questions:[{type:"explain",q:"Що Geyser plugins роблять і навіщо?",ideal:"Plugins streaming live data з validator: account changes, slots, TXs, blocks. Power indexers, real-time UIs, bots, analytics. Без Geyser apps мусили б poll RPC — high latency, high load. RPC providers run Geyser-enabled nodes commercially (Helius, Triton). Module 10.1.",explanation:""},{type:"compare",q:"Full snapshot vs incremental?",ideal:"Full: complete accountsDB at slot, ~80-100GB mainnet, created every ~25k slots. Incremental: delta from last full, ~1GB, created every ~100 slots. Fast catch-up: download recent full + incremental → minutes vs days of replay. Module 10.2.",explanation:""},{type:"mcq",q:"DoubleZero роботи:",options:["Dedicated network для validator-to-validator traffic","Lower latency для shreds + votes vs public internet","Permissioned access з DZ token rewards","Replaces SPL Token Program"],correct:[0,1,2],explanation:"Module 10.3."},{type:"compare",q:"SIMD vs JIP?",ideal:"SIMD = Solana Foundation, cluster-wide protocol changes (e.g., Alpenglow). Vote-weighted by validators. JIP = Jito DAO, application-level changes (BAM subsidy, JitoSOL delegation). Vote by JTO holders. Different scopes. Both follow proposal → discussion → vote → implementation pattern. Module 10.4.",explanation:""},{type:"mcq",q:"Per content style memory, як LumLabs writing про Jito governance?",options:['Attribute source clearly ("Jito announced")','Use "we" коли referring до Jito decisions',"Avoid imperative voice","No em-dashes"],correct:[0,2,3],explanation:"LumLabs external observer, не Jito team. Module 10.4."},{type:"command",q:"Як check DoubleZero tunnel status?",accepts:["doublezero status"],ideal:"doublezero status",explanation:"Module 10.3."},{type:"explain",q:"Чому cNFTs (state compression) можливо для million-scale collections, а standard NFTs ні?",ideal:`Standard NFT ≈ 0.008 SOL each (mint + metadata + ATA rent). 1M NFTs = 8500 SOL ≈ $1.7M. Not feasible.

Compressed NFT (cNFT): Merkle tree stores root hash representing up to billion+ tokens. Individual NFT data off-chain (IPFS + RPC indexer cache). ~0.00001 SOL per NFT. 1M = 10 SOL ≈ $2000.

Trade-off: cNFT depends on RPC indexer для off-chain data lookup. Без indexer = NFTs hard to access. Standard NFT data on-chain, always accessible. Module 10.6.`,explanation:""},{type:"compare",q:"Pyth vs Switchboard oracles?",ideal:`Pyth: institutional. First-party publishers (Jane Street, Wintermute, etc.) push prices directly. Sub-second latency. Focus financial markets. Pull-based. Pay-per-update.

Switchboard: general-purpose decentralized. Permissionless node operators run feeds. Broader data types (sports, weather, custom). Often free для consumers. VRF service included.

Difference: Pyth institutional trust, Switchboard decentralized. Most DeFi uses Pyth для prices, Switchboard для custom data. Module 10.7.`,explanation:""}]};return(p,e)=>{const o=n("Quiz");return s(),i("div",null,[e[0]||(e[0]=a("h1",{id:"⭐-module-10-—-final-quiz",tabindex:"-1"},[r("⭐ Module 10 — Final quiz "),a("a",{class:"header-anchor",href:"#⭐-module-10-—-final-quiz","aria-label":'Permalink to "⭐ Module 10 — Final quiz"'},"​")],-1)),l(o,{data:t}),e[1]||(e[1]=d('<hr><p>🎓 <strong>Congratulations!</strong> Ти пройшла повний curriculum. Modules 0-10 covered all fundamental знання що operating Solana validator потребує.</p><p><strong>Recommendation:</strong> Bookmark глосарій + return to specific modules коли потрібно. Re-take quizes раз на квартал щоб maintain knowledge.</p><p><strong>Попередньо:</strong> <a href="/module-10/4-governance">← 4. Governance</a> | <strong>Course start:</strong> <a href="/">Home</a></p>',4))])}}});export{h as __pageData,f as default};
